// Tally envoie les champs dans data.fields[]
// Ce noeud extrait proprement le prénom et l'email

const body = $input.first().json.body || $input.first().json;
const fields = body?.data?.fields || [];

let prenom = '';
let email = '';

for (const field of fields) {
  const label = (field.label || '').toLowerCase().trim();
  const value = field.value || '';

  if (label.includes('prenom') || label.includes('prénom') || label.includes('nom') || label.includes('name')) {
    prenom = value.trim();
  }
  if (label.includes('mail') || label.includes('email') || field.type === 'INPUT_EMAIL') {
    email = value.trim().toLowerCase();
  }
}

// Fallback si les labels ne correspondent pas
if (!prenom && fields[0]) prenom = fields[0].value || 'Ami';
if (!email && fields[1]) email = fields[1].value || '';

if (!email) {
  throw new Error('Email non trouvé dans la soumission Tally');
}

const prenomFormate = prenom
  ? prenom.charAt(0).toUpperCase() + prenom.slice(1).toLowerCase()
  : 'Ami';

return [{
  json: {
    prenom: prenomFormate,
    email: email,
    source: 'tally-lead-magnet',
    timestamp: new Date().toISOString()
  }
}];
